// =============== 검색/조회 헬퍼 ===============

/** 서비스코드(svcCd)로 단건 조회 */
export function getApiSpec(code: string): ApiSpec | undefined {
  const upper = code.toUpperCase();
  return CATALOG.find((c) => c.code === upper);
}

export interface SearchQuery {
  /** 키워드: name/description/tags/category/code 부분 매칭 (대소문자 무시) */
  q?: string;
  /** 카테고리 정확 매칭 */
  category?: string;
  /** 보유연도가 이 연도를 포함하는 것만 (예: 2024) */
  year?: number;
  /** 결과 최대 개수 (기본 20) */
  limit?: number;
}

/** 카탈로그 검색 */
export function searchCatalog(query: SearchQuery = {}): ApiSpec[] {
  const { q, category, year, limit = 20 } = query;
  const needle = q?.toLowerCase().trim();
  let results = CATALOG;
  if (category) {
    results = results.filter((c) => c.category === category);
  }
  if (needle) {
    results = results.filter((c) =>
      c.name.toLowerCase().includes(needle) ||
      c.description.toLowerCase().includes(needle) ||
      c.tags.toLowerCase().includes(needle) ||
      c.category.toLowerCase().includes(needle) ||
      c.code.toLowerCase().includes(needle)
    );
  }
  if (year !== undefined) {
    results = results.filter((c) => {
      const m = c.years.match(/(\d{4})\s*~\s*(\d{4})/);
      if (!m) return false;
      const start = parseInt(m[1], 10);
      const end = parseInt(m[2], 10);
      return year >= start && year <= end;
    });
  }
  return results.slice(0, limit);
}

/** 모든 카테고리 목록 (개수 내림차순) */
export function listCategories(): { category: string; count: number }[] {
  const counts = new Map<string, number>();
  for (const c of CATALOG) {
    counts.set(c.category, (counts.get(c.category) ?? 0) + 1);
  }
  return Array.from(counts.entries())
    .map(([category, count]) => ({ category, count }))
    .sort((a, b) => b.count - a.count);
}
